window.FUNGAL_TOPICS=[{"slug":"general","title":{"en":"General Fungal Infections","ar":"أساسيات العدوى الفطرية"},"count":10,"types":{"MCQ":6,"Case":2,"Treatment":2},"summary":{"en":"Dermatophyte biology, host source, KOH diagnosis, and principles of topical versus systemic therapy.","ar":"بيولوجيا الفطريات الجلدية ومصادر العدوى وتشخيص KOH ومبادئ العلاج الموضعي مقابل الجهازي."},"pearl":{"en":"The infected structure—skin, hair, or nail—often determines whether topical therapy is enough.","ar":"البنية المصابة—الجلد أو الشعر أو الظفر—غالبًا هي التي تحدد هل يكفي العلاج الموضعي أم لا."},"image":"assets/images/chapters/fungal/fungal-01.webp"},{"slug":"tinea-pedis","title":{"en":"Tinea Pedis","ar":"سعفة القدم"},"count":18,"types":{"MCQ":7,"Case":5,"Treatment":4,"Image":2},"summary":{"en":"Interdigital, moccasin, vesiculobullous, and ulcerative patterns with complications and recurrence prevention.","ar":"الأنماط بين الأصابع وشكل الحذاء والحويصلي والتقرحي، مع المضاعفات والوقاية من التكرار."},"pearl":{"en":"Treat the fungus and the moist environment that keeps it returning.","ar":"عالج الفطر والبيئة الرطبة التي تساعده على التكرار معًا."},"image":"assets/images/chapters/fungal/fungal-q027.webp"},{"slug":"tinea-cruris","title":{"en":"Tinea Cruris","ar":"سعفة الأرفاغ"},"count":16,"types":{"MCQ":6,"Case":5,"Treatment":4,"Image":1},"summary":{"en":"Groin morphology, scrotal sparing, reservoirs, steroid misuse, resistance, and treatment selection.","ar":"شكل إصابة الأربية وسلامة الصفن والمستودعات وسوء استخدام الكورتيزون والمقاومة واختيار العلاج."},"pearl":{"en":"An active scaly border with relative scrotal sparing strongly favors tinea cruris.","ar":"الحافة النشطة المتقشرة مع سلامة كيس الصفن نسبيًا ترجح سعفة الأرفاغ."},"image":"assets/images/chapters/fungal/fungal-q044.webp"},{"slug":"onychomycosis","title":{"en":"Onychomycosis","ar":"فطار الأظافر"},"count":22,"types":{"MCQ":8,"Case":7,"Treatment":4,"Image":3},"summary":{"en":"Clinical subtypes, diagnostic confirmation, oral therapy, monitoring, and relapse prevention.","ar":"الأنواع السريرية وتأكيد التشخيص والعلاج الفموي والمتابعة والوقاية من الانتكاس."},"pearl":{"en":"Confirm fungus before prolonged systemic therapy because many nail disorders mimic onychomycosis.","ar":"أكد وجود الفطر قبل العلاج الجهازي الطويل لأن أمراضًا كثيرة بالأظافر تشبه فطار الأظافر."},"image":"assets/images/chapters/fungal/fungal-q064.webp"},{"slug":"tinea-capitis","title":{"en":"Tinea Capitis","ar":"سعفة الرأس"},"count":22,"types":{"MCQ":8,"Case":7,"Treatment":4,"Image":3},"summary":{"en":"Scalp patterns, ectothrix and endothrix clues, kerion, systemic treatment, and household control.","ar":"أنماط فروة الرأس وعلامات ectothrix وendothrix والكيريون والعلاج الجهازي والسيطرة داخل المنزل."},"pearl":{"en":"Hair-shaft infection requires systemic therapy; topical treatment alone is not enough.","ar":"إصابة ساق الشعرة تحتاج علاجًا جهازيًا، ولا يكفي العلاج الموضعي وحده."},"image":"assets/images/chapters/fungal/fungal-q086.webp"},{"slug":"tinea-incognito","title":{"en":"Tinea Incognito","ar":"السعفة المتخفية"},"count":12,"types":{"MCQ":4,"Case":4,"Treatment":3,"Image":1},"summary":{"en":"Steroid-modified dermatophytosis, altered morphology, diagnostic recovery, and correct antifungal management.","ar":"السعفة المعدلة بالكورتيزون وتغير شكلها واستعادة التشخيص والتدبير الصحيح بالمضادات الفطرية."},"pearl":{"en":"Temporary improvement with steroid does not equal cure; it may hide an expanding fungal infection.","ar":"التحسن المؤقت بالكورتيزون لا يعني الشفاء؛ فقد يخفي عدوى فطرية تتوسع."},"image":"assets/images/chapters/fungal/fungal-q100.webp"},{"slug":"pityriasis-versicolor","title":{"en":"Pityriasis Versicolor","ar":"النخالية المبرقشة"},"count":18,"types":{"MCQ":6,"Case":5,"Treatment":5,"Image":2},"summary":{"en":"Malassezia overgrowth, pigment change, fine scale, KOH clues, therapy, and frequent recurrence.","ar":"فرط نمو Malassezia وتغير اللون والقشور الدقيقة وعلامات KOH والعلاج والتكرار الشائع."},"pearl":{"en":"Pigment may take longer to normalize than the fungal infection itself.","ar":"قد يحتاج لون الجلد وقتًا أطول للعودة لطبيعته بعد القضاء على الفطر."},"image":"assets/images/chapters/fungal/fungal-q117.webp"},{"slug":"candidiasis","title":{"en":"Candidiasis","ar":"داء المبيضات"},"count":24,"types":{"MCQ":8,"Case":8,"Treatment":6,"Image":2},"summary":{"en":"Intertrigo, mucocutaneous patterns, risk factors, satellite lesions, treatment, and referral clues.","ar":"التهاب الثنيات والأنماط المخاطية الجلدية وعوامل الخطورة والآفات التابعة والعلاج وعلامات الإحالة."},"pearl":{"en":"Moist beefy-red erythema with satellite pustules is a classic candidal pattern.","ar":"الحمامى الرطبة الحمراء الزاهية مع البثور التابعة نمط كلاسيكي للمبيضات."},"image":"assets/images/chapters/fungal/fungal-q141.webp"},{"slug":"tinea-nigra","title":{"en":"Tinea Nigra","ar":"السعفة السوداء"},"count":8,"types":{"MCQ":2,"Case":2,"Treatment":3,"Image":1},"summary":{"en":"Superficial brown-black palm or sole macules, differential diagnosis, microscopy, and topical treatment.","ar":"لطخات بنية سوداء سطحية على الراحة أو الأخمص والتشخيص التفريقي والفحص المجهري والعلاج الموضعي."},"pearl":{"en":"A noninflammatory dark palm lesion should still be tested before assuming a melanocytic disorder.","ar":"اللطخة الداكنة غير الملتهبة على راحة اليد تحتاج فحصًا قبل افتراض أنها آفة صبغية."},"image":"assets/images/chapters/fungal/fungal-q150.webp"}];
