window.FUNGAL_QUESTIONS=[{"id":"Q001","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"MCQ","difficulty":"Medium","source":"PDF p. 47","question":{"en":"Which dermatophyte genus characteristically infects skin and hair but not nails?","ar":"أي جنس من الفطريات الجلدية يصيب الجلد والشعر عادةً ولا يصيب الأظافر؟"},"options":[{"letter":"A","en":"Microsporum","ar":"Microsporum"},{"letter":"B","en":"Trichophyton","ar":"Trichophyton"},{"letter":"C","en":"Epidermophyton","ar":"Epidermophyton"},{"letter":"D","en":"Candida","ar":"Candida"}],"correct":"A","explanation":{"en":"Microsporum species infect keratinized skin and hair. Trichophyton can infect skin, hair, and nails, whereas Epidermophyton infects skin and nails.","ar":"تصيب أنواع Microsporum الجلد المتقرن والشعر. ويمكن لـ Trichophyton إصابة الجلد والشعر والأظافر، بينما يصيب Epidermophyton الجلد والأظافر."},"reasoning":{"en":"The tissue distribution is the key discriminator: hair involvement with no nail involvement points to Microsporum.","ar":"توزيع الأنسجة هو مفتاح التمييز؛ إصابة الشعر دون الأظافر تشير إلى Microsporum."},"image":null},{"id":"Q002","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"MCQ","difficulty":"Hard","source":"PDF p. 47","question":{"en":"What best explains why dermatophytes usually remain superficial?","ar":"ما أفضل تفسير لبقاء الفطريات الجلدية غالبًا سطحية؟"},"options":[{"letter":"A","en":"They require keratin for growth","ar":"تحتاج إلى الكيراتين للنمو"},{"letter":"B","en":"They are destroyed by sebum","ar":"يدمرها الزهم"},{"letter":"C","en":"They cannot form spores","ar":"لا تستطيع تكوين أبواغ"},{"letter":"D","en":"They only grow below 20°C","ar":"تنمو فقط تحت 20 درجة مئوية"}],"correct":"A","explanation":{"en":"Dermatophytes are keratinophilic and primarily invade the stratum corneum, hair, and nails rather than viable deep tissue.","ar":"الفطريات الجلدية محبة للكيراتين، ولذلك تغزو أساسًا الطبقة القرنية والشعر والأظافر بدلًا من الأنسجة الحية العميقة."},"reasoning":{"en":"A pathogen limited by its nutrient requirement to keratinized structures produces a superficial pattern.","ar":"اعتماد الممرض على الكيراتين يحصره غالبًا في البنى المتقرنة ويؤدي إلى نمط سطحي."},"image":null},{"id":"Q003","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"MCQ","difficulty":"Medium","source":"PDF p. 48","question":{"en":"Which source category usually causes a more acute and inflammatory dermatophyte infection in humans?","ar":"أي فئة من مصادر الفطريات الجلدية تُسبب عادةً عدوى أكثر حدة والتهابًا في الإنسان؟"},"options":[{"letter":"A","en":"Zoophilic species","ar":"الأنواع الحيوانية المصدر"},{"letter":"B","en":"Anthropophilic species","ar":"الأنواع البشرية المصدر"},{"letter":"C","en":"Normal bacterial flora","ar":"الفلورا البكتيرية الطبيعية"},{"letter":"D","en":"Nonpathogenic yeasts only","ar":"الخمائر غير الممرضة فقط"}],"correct":"A","explanation":{"en":"Zoophilic dermatophytes are adapted to animals and tend to provoke an acute inflammatory response after transmission to humans.","ar":"الفطريات الجلدية الحيوانية المصدر متكيفة مع الحيوانات، وتميل إلى إحداث استجابة التهابية حادة عند انتقالها إلى الإنسان."},"reasoning":{"en":"A poorly adapted host-pathogen relationship often triggers more inflammation than a chronic human-adapted organism.","ar":"عدم تكيف الفطر جيدًا مع العائل البشري يؤدي غالبًا إلى التهاب أشد من الأنواع المتكيفة مع الإنسان."},"image":null},{"id":"Q004","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"MCQ","difficulty":"Medium","source":"PDF p. 47","question":{"en":"Which finding most strongly suggests a deep fungal infection rather than a superficial dermatophytosis?","ar":"أي علامة ترجح عدوى فطرية عميقة بدلًا من عدوى جلدية سطحية؟"},"options":[{"letter":"A","en":"Tumefaction with draining sinuses and grains","ar":"تورم مع ناسور مفرغ وحبيبات"},{"letter":"B","en":"Annular plaque with central clearing","ar":"لويحة حلقية ذات تفريغ مركزي"},{"letter":"C","en":"Fine scale limited to the stratum corneum","ar":"قشور دقيقة محدودة بالطبقة القرنية"},{"letter":"D","en":"Mild interdigital itching","ar":"حكة بسيطة بين الأصابع"}],"correct":"A","explanation":{"en":"The classic triad of mycetoma is tumefaction, draining sinuses, and discharge of grains, indicating dermal and subcutaneous involvement.","ar":"الثلاثي الكلاسيكي للميستوما هو التورم والناسور المفرغ وخروج الحبيبات، ما يدل على إصابة الأدمة والأنسجة تحت الجلد."},"reasoning":{"en":"Sinus formation and grains require deeper tissue invasion; simple ringworm remains in keratinized structures.","ar":"تكوين النواسير والحبيبات يتطلب غزوًا عميقًا للأنسجة، بخلاف السعفة السطحية."},"image":null},{"id":"Q005","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"MCQ","difficulty":"Medium","source":"PDF p. 46","question":{"en":"Which diagnostic test directly demonstrates fungal elements such as septate hyphae in skin scrapings?","ar":"أي اختبار يُظهر مباشرة العناصر الفطرية مثل الخيوط الفطرية المقسمة في كشط الجلد؟"},"options":[{"letter":"A","en":"Potassium hydroxide preparation","ar":"فحص هيدروكسيد البوتاسيوم KOH"},{"letter":"B","en":"Complete blood count","ar":"صورة دم كاملة"},{"letter":"C","en":"Patch testing","ar":"اختبار الرقعة"},{"letter":"D","en":"Serum IgE only","ar":"IgE في المصل فقط"}],"correct":"A","explanation":{"en":"KOH dissolves keratin and allows hyphae or yeast forms to be visualized microscopically.","ar":"يذيب KOH الكيراتين ويتيح رؤية الخيوط الفطرية أو أشكال الخميرة بالمجهر."},"reasoning":{"en":"The test should target the organism in the affected keratin, making direct microscopy the most relevant option.","ar":"يجب أن يستهدف الاختبار الكائن داخل الكيراتين المصاب، لذلك يكون الفحص المباشر هو الأنسب."},"image":null},{"id":"Q006","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"MCQ","difficulty":"Easy","source":"PDF p. 47","question":{"en":"Which organism is a lipophilic yeast rather than a dermatophyte?","ar":"أي كائن يُعد خميرة محبة للدهون وليس من الفطريات الجلدية؟"},"options":[{"letter":"A","en":"Malassezia furfur","ar":"Malassezia furfur"},{"letter":"B","en":"Trichophyton rubrum","ar":"Trichophyton rubrum"},{"letter":"C","en":"Microsporum canis","ar":"Microsporum canis"},{"letter":"D","en":"Epidermophyton floccosum","ar":"Epidermophyton floccosum"}],"correct":"A","explanation":{"en":"Malassezia is a lipophilic yeast associated with pityriasis versicolor; the other organisms are dermatophytes.","ar":"Malassezia خميرة محبة للدهون وترتبط بالنخالية المبرقشة، بينما الكائنات الأخرى فطريات جلدية."},"reasoning":{"en":"The clinical group is identified by biology: Malassezia thrives in sebaceous areas and is not a keratinophilic dermatophyte genus.","ar":"يُحدد التصنيف من طبيعة الكائن؛ تنمو Malassezia في المناطق الدهنية وليست جنسًا من الفطريات الجلدية المحبة للكيراتين."},"image":null},{"id":"Q007","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"Case","difficulty":"Medium","source":"PDF p. 48","question":{"en":"A child develops a highly inflamed ring-shaped plaque after handling an infected kitten. Which fungal source is most likely?","ar":"أصيب طفل بلويحة حلقية شديدة الالتهاب بعد التعامل مع قطة مصابة. ما المصدر الفطري الأرجح؟"},"options":[{"letter":"A","en":"Zoophilic dermatophyte","ar":"فطر جلدي حيواني المصدر"},{"letter":"B","en":"Anthropophilic dermatophyte","ar":"فطر جلدي بشري المصدر"},{"letter":"C","en":"Candida colonization","ar":"استعمار بالكانديدا"},{"letter":"D","en":"Malassezia overgrowth","ar":"فرط نمو Malassezia"}],"correct":"A","explanation":{"en":"Animal exposure plus a brisk inflammatory reaction strongly suggests a zoophilic dermatophyte, such as Microsporum canis.","ar":"التعرض لحيوان مع استجابة التهابية شديدة يرجح فطرًا جلديًا حيواني المصدر مثل Microsporum canis."},"reasoning":{"en":"Link the epidemiology (kitten contact) with the expected host response (acute inflammation).","ar":"اربط بين الوبائيات، وهي ملامسة القطة، والاستجابة المتوقعة، وهي الالتهاب الحاد."},"image":null},{"id":"Q008","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"Case","difficulty":"Medium","source":"PDF p. 47","question":{"en":"A patient has a chronic, slowly progressive annular rash with minimal inflammation that repeatedly spreads among family members. Which host-specific group is most consistent?","ar":"مريض لديه طفح حلقي مزمن بطيء التقدم مع التهاب بسيط وينتقل بين أفراد الأسرة. أي مجموعة تتوافق أكثر؟"},"options":[{"letter":"A","en":"Anthropophilic dermatophytes","ar":"الفطريات الجلدية البشرية المصدر"},{"letter":"B","en":"Zoophilic dermatophytes","ar":"الفطريات الجلدية الحيوانية المصدر"},{"letter":"C","en":"Geophilic dermatophytes","ar":"الفطريات الجلدية الترابية المصدر"},{"letter":"D","en":"Invasive molds","ar":"العفن الغازي"}],"correct":"A","explanation":{"en":"Human-adapted anthropophilic species often cause chronic, minimally inflammatory infections and spread person to person.","ar":"الأنواع البشرية المتكيفة مع الإنسان تسبب غالبًا عدوى مزمنة قليلة الالتهاب وتنتقل من شخص لآخر."},"reasoning":{"en":"Chronicity, low inflammation, and household transmission all fit a human-adapted organism.","ar":"الزمن المزمن وقلة الالتهاب والانتقال داخل الأسرة كلها تدعم كائنًا متكيفًا مع الإنسان."},"image":null},{"id":"Q009","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"Treatment","difficulty":"Hard","source":"PDF p. 46","question":{"en":"A localized superficial dermatophyte infection is confirmed with no hair or nail involvement. What is the most appropriate initial treatment principle?","ar":"تم تأكيد عدوى فطرية جلدية سطحية موضعية دون إصابة الشعر أو الأظافر. ما مبدأ العلاج الأولي الأنسب؟"},"options":[{"letter":"A","en":"Use a topical azole or allylamine","ar":"استخدام أزول موضعي أو أليلامين"},{"letter":"B","en":"Start IV amphotericin B","ar":"بدء أمفوتيريسين ب وريدي"},{"letter":"C","en":"Use topical nystatin for every dermatophyte","ar":"استخدام نيستاتين موضعي لكل الفطريات الجلدية"},{"letter":"D","en":"Give systemic antibiotics","ar":"إعطاء مضادات حيوية جهازية"}],"correct":"A","explanation":{"en":"Localized skin dermatophytosis is usually treated with a topical agent such as clotrimazole or terbinafine.","ar":"تعالج السعفة الجلدية الموضعية غالبًا بمضاد فطري موضعي مثل كلوتريمازول أو تيربينافين."},"reasoning":{"en":"Disease limited to accessible keratinized skin does not require systemic or intravenous therapy.","ar":"العدوى المحدودة بالجلد المتقرن القابل للعلاج الموضعي لا تحتاج عادةً إلى علاج جهازي أو وريدي."},"image":null},{"id":"Q010","topic":"general","topicEn":"General Fungal Infections","topicAr":"أساسيات العدوى الفطرية","type":"Treatment","difficulty":"Medium","source":"PDF p. 46","question":{"en":"Which situation most clearly justifies systemic antifungal therapy rather than topical therapy alone?","ar":"أي حالة تبرر بوضوح استخدام علاج فطري جهازي بدل العلاج الموضعي وحده؟"},"options":[{"letter":"A","en":"Scalp hair-shaft infection","ar":"عدوى بفروة الرأس وساق الشعرة"},{"letter":"B","en":"A single small tinea corporis plaque","ar":"لويحة سعفة جسم صغيرة واحدة"},{"letter":"C","en":"Mild localized interdigital scaling","ar":"قشور بسيطة موضعية بين الأصابع"},{"letter":"D","en":"A transient dry patch with negative KOH","ar":"بقعة جافة عابرة مع KOH سلبي"}],"correct":"A","explanation":{"en":"Hair and nail infections generally require systemic therapy because topical agents do not adequately penetrate the involved structures.","ar":"تحتاج عدوى الشعر والأظافر غالبًا إلى علاج جهازي لأن الأدوية الموضعية لا تخترق البنى المصابة بكفاءة كافية."},"reasoning":{"en":"The anatomic site determines penetration; involvement within the hair shaft cannot be eradicated by surface treatment alone.","ar":"الموقع التشريحي يحدد الاختراق؛ فالعدوى داخل ساق الشعرة لا يمكن القضاء عليها بالعلاج السطحي وحده."},"image":null},{"id":"Q011","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"MCQ","difficulty":"Medium","source":"PDF p. 49","question":{"en":"Which organism is the most common cause of tinea pedis?","ar":"ما الكائن الأكثر شيوعًا في التسبب بسعفة القدم؟"},"options":[{"letter":"A","en":"Trichophyton rubrum","ar":"Trichophyton rubrum"},{"letter":"B","en":"Candida albicans","ar":"Candida albicans"},{"letter":"C","en":"Malassezia globosa","ar":"Malassezia globosa"},{"letter":"D","en":"Hortaea werneckii","ar":"Hortaea werneckii"}],"correct":"A","explanation":{"en":"Trichophyton rubrum is the leading cause of tinea pedis, particularly chronic disease.","ar":"يُعد Trichophyton rubrum السبب الأكثر شيوعًا لسعفة القدم، خاصة الحالات المزمنة."},"reasoning":{"en":"The organism most associated with chronic dermatophytosis of feet is T. rubrum.","ar":"الكائن الأكثر ارتباطًا بالسعفة المزمنة للقدم هو T. rubrum."},"image":null},{"id":"Q012","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"MCQ","difficulty":"Medium","source":"PDF p. 50","question":{"en":"Which toe-web space is most commonly affected in interdigital tinea pedis?","ar":"أي فراغ بين أصابع القدم يُصاب غالبًا في سعفة القدم بين الأصابع؟"},"options":[{"letter":"A","en":"Fourth to fifth toe space","ar":"بين الإصبعين الرابع والخامس"},{"letter":"B","en":"First to second toe space","ar":"بين الإصبعين الأول والثاني"},{"letter":"C","en":"Second to third toe space only","ar":"بين الثاني والثالث فقط"},{"letter":"D","en":"All spaces equally","ar":"كل الفراغات بالتساوي"}],"correct":"A","explanation":{"en":"The interdigital form most often begins in the fourth toe web, where moisture and occlusion are prominent.","ar":"يبدأ الشكل بين الأصابع غالبًا في الفراغ الرابع حيث تزداد الرطوبة والانغلاق."},"reasoning":{"en":"Maceration is greatest in the tightest, least ventilated web space.","ar":"تكون التهوية أقل والرطوبة أعلى في أضيق فراغ بين الأصابع."},"image":null},{"id":"Q013","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"MCQ","difficulty":"Easy","source":"PDF p. 50","question":{"en":"Diffuse dry scaling over the sole, heel, and lateral foot is characteristic of which type?","ar":"القشور الجافة المنتشرة على باطن القدم والكعب والجوانب تميز أي نوع؟"},"options":[{"letter":"A","en":"Hyperkeratotic moccasin type","ar":"النوع مفرط التقرن بشكل الحذاء"},{"letter":"B","en":"Interdigital type","ar":"النوع بين الأصابع"},{"letter":"C","en":"Vesiculobullous type","ar":"النوع الحويصلي الفقاعي"},{"letter":"D","en":"Ulcerative type","ar":"النوع التقرحي"}],"correct":"A","explanation":{"en":"The moccasin form produces diffuse hyperkeratosis and scaling around the sole and sides of the foot.","ar":"يسبب نوع الحذاء فرط تقرن وقشورًا منتشرة حول باطن القدم وجوانبها."},"reasoning":{"en":"The distribution resembles the area covered by a moccasin shoe.","ar":"يشبه التوزيع المنطقة التي يغطيها الحذاء المغلق."},"image":null},{"id":"Q014","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"MCQ","difficulty":"Medium","source":"PDF p. 50","question":{"en":"Pruritic vesicles on the medial plantar arch most strongly suggest:","ar":"الحويصلات الحاكة على الجانب الإنسي من باطن القدم ترجح:"},"options":[{"letter":"A","en":"Vesiculobullous tinea pedis","ar":"سعفة القدم الحويصلية الفقاعية"},{"letter":"B","en":"Moccasin tinea pedis","ar":"سعفة القدم بشكل الحذاء"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Onychomycosis","ar":"فطار الأظافر"}],"correct":"A","explanation":{"en":"The inflammatory vesiculobullous form typically produces vesicles or bullae on the medial plantar surface.","ar":"يظهر النوع الالتهابي الحويصلي الفقاعي عادةً بحويصلات أو فقاعات على السطح الأخمصي الإنسي."},"reasoning":{"en":"Morphology plus plantar location differentiates it from dry moccasin disease.","ar":"يجمع التشخيص بين شكل الحويصلات وموقعها الأخمصي، ما يميزه عن النوع الجاف."},"image":null},{"id":"Q015","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"MCQ","difficulty":"Easy","source":"PDF p. 51","question":{"en":"Which drug is ineffective against dermatophyte tinea pedis?","ar":"أي دواء غير فعال ضد سعفة القدم الناتجة عن الفطريات الجلدية؟"},"options":[{"letter":"A","en":"Nystatin","ar":"نيستاتين"},{"letter":"B","en":"Terbinafine","ar":"تيربينافين"},{"letter":"C","en":"Clotrimazole","ar":"كلوتريمازول"},{"letter":"D","en":"Naftifine","ar":"نافتيفين"}],"correct":"A","explanation":{"en":"Nystatin is active against Candida but not dermatophytes, so it should not be selected for typical tinea pedis.","ar":"النيستاتين فعال ضد Candida لكنه غير فعال ضد الفطريات الجلدية، لذلك لا يُختار لسعفة القدم المعتادة."},"reasoning":{"en":"Matching antifungal spectrum to the organism prevents predictable treatment failure.","ar":"مطابقة طيف الدواء مع الكائن المسبب تمنع فشل العلاج المتوقع."},"image":null},{"id":"Q016","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"MCQ","difficulty":"Hard","source":"PDF p. 51","question":{"en":"A vesicular eruption on the hands caused by hypersensitivity to a fungal infection on the feet is called:","ar":"الطفح الحويصلي على اليدين الناتج عن فرط الحساسية لعدوى فطرية بالقدمين يسمى:"},"options":[{"letter":"A","en":"Dermatophytid reaction","ar":"تفاعل Dermatophytid"},{"letter":"B","en":"Bacterial cellulitis","ar":"التهاب النسيج الخلوي البكتيري"},{"letter":"C","en":"Koebner phenomenon","ar":"ظاهرة كوبنر"},{"letter":"D","en":"Toxic erythema","ar":"الحمامى السمية"}],"correct":"A","explanation":{"en":"An id reaction is an autoeczematization response distant from the primary fungal site and contains no fungus in the secondary lesions.","ar":"تفاعل الـ id هو استجابة إكزيمية بعيدة عن موقع الفطر الأساسي، ولا تحتوي الآفات الثانوية على الفطر."},"reasoning":{"en":"The distant sterile vesicles reflect immune hypersensitivity, not spread of the organism to the hands.","ar":"الحويصلات البعيدة المعقمة تعكس فرط حساسية مناعي وليس انتقال الفطر إلى اليدين."},"image":null},{"id":"Q017","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"MCQ","difficulty":"Medium","source":"PDF p. 52","question":{"en":"Which preventive measure is most useful for reducing recurrent tinea pedis?","ar":"أي إجراء وقائي يفيد أكثر في تقليل تكرار سعفة القدم؟"},"options":[{"letter":"A","en":"Keep feet and footwear dry","ar":"الحفاظ على جفاف القدمين والأحذية"},{"letter":"B","en":"Wear tighter synthetic shoes","ar":"ارتداء أحذية صناعية أكثر ضيقًا"},{"letter":"C","en":"Share towels after washing","ar":"مشاركة المناشف بعد غسلها"},{"letter":"D","en":"Stop treatment once itching improves","ar":"إيقاف العلاج بمجرد تحسن الحكة"}],"correct":"A","explanation":{"en":"Moisture control, breathable footwear, clean socks, and antifungal treatment of shoes reduce recurrence.","ar":"تقليل الرطوبة وارتداء أحذية جيدة التهوية وجوارب نظيفة ومعالجة الأحذية بمضاد فطري يقلل التكرار."},"reasoning":{"en":"The fungus thrives in warm, moist, occluded environments, so environmental control is essential.","ar":"ينمو الفطر في البيئة الدافئة الرطبة المغلقة، لذا يعد التحكم في البيئة جزءًا أساسيًا من الوقاية."},"image":null},{"id":"Q018","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Case","difficulty":"Hard","source":"PDF p. 50","question":{"en":"A 28-year-old athlete has itching, whitish maceration, and painful fissures between the fourth and fifth toes. What is the most likely diagnosis?","ar":"رياضي عمره 28 عامًا يعاني حكة وتميعًا أبيض وشقوقًا مؤلمة بين الإصبعين الرابع والخامس. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Interdigital tinea pedis","ar":"سعفة القدم بين الأصابع"},{"letter":"B","en":"Moccasin tinea pedis","ar":"سعفة القدم بشكل الحذاء"},{"letter":"C","en":"Tinea cruris","ar":"سعفة الأرفاغ"},{"letter":"D","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"}],"correct":"A","explanation":{"en":"The location, maceration, scaling, and fissuring are classic for interdigital tinea pedis.","ar":"الموقع والتميع والقشور والتشققات علامات كلاسيكية لسعفة القدم بين الأصابع."},"reasoning":{"en":"The toe-web morphology is more specific than the nonspecific symptom of itching.","ar":"شكل الآفة بين الأصابع أكثر نوعية من عرض الحكة غير النوعي."},"image":null},{"id":"Q019","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Case","difficulty":"Medium","source":"PDF p. 50","question":{"en":"A patient has bilateral chronic dry scaling that wraps around the soles and sides of both feet. Which pattern is present?","ar":"مريض لديه قشور جافة مزمنة ثنائية الجانب تحيط بباطن القدمين وجوانبهما. ما النمط الموجود؟"},"options":[{"letter":"A","en":"Moccasin-type tinea pedis","ar":"سعفة القدم من نوع الحذاء"},{"letter":"B","en":"Ulcerative tinea pedis","ar":"سعفة القدم التقرحية"},{"letter":"C","en":"Acute bacterial impetigo","ar":"القوباء البكتيرية الحادة"},{"letter":"D","en":"Tinea capitis","ar":"سعفة الرأس"}],"correct":"A","explanation":{"en":"Diffuse plantar and lateral hyperkeratotic scaling is the defining pattern of moccasin tinea pedis.","ar":"القشور مفرطة التقرن المنتشرة أخمصيًا وجانبيًا هي النمط المميز لسعفة القدم بشكل الحذاء."},"reasoning":{"en":"The “wraparound” distribution is the clinical clue to the moccasin pattern.","ar":"التوزيع المحيط بالقدم هو الدليل السريري على نمط الحذاء."},"image":null},{"id":"Q020","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Case","difficulty":"Medium","source":"PDF p. 50","question":{"en":"A patient develops intensely itchy grouped vesicles on the arch of the foot after a hot, humid week. Which type is most likely?","ar":"ظهرت لدى مريض حويصلات مجمعة شديدة الحكة على قوس القدم بعد أسبوع حار ورطب. أي نوع هو الأرجح؟"},"options":[{"letter":"A","en":"Vesiculobullous tinea pedis","ar":"سعفة القدم الحويصلية الفقاعية"},{"letter":"B","en":"Interdigital candidiasis","ar":"داء المبيضات بين الأصابع"},{"letter":"C","en":"DLSO","ar":"فطار الأظافر تحت الظفر البعيد الجانبي"},{"letter":"D","en":"Tinea nigra","ar":"السعفة السوداء"}],"correct":"A","explanation":{"en":"The acute inflammatory type often presents with pruritic vesicles on the medial plantar arch.","ar":"يظهر النوع الالتهابي الحاد غالبًا بحويصلات حاكة على قوس القدم الأخمصي الإنسي."},"reasoning":{"en":"Climate supports fungal activity, but the vesicular plantar morphology identifies the subtype.","ar":"يساعد المناخ على نشاط الفطر، لكن الشكل الحويصلي الأخمصي هو الذي يحدد النوع."},"image":null},{"id":"Q021","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Case","difficulty":"Medium","source":"PDF p. 51","question":{"en":"A diabetic patient has erosions, ulcers, foul odor, and severe pain involving the feet. Which tinea pedis form should be suspected?","ar":"مريض سكري لديه تآكلات وقرح ورائحة كريهة وألم شديد بالقدمين. أي شكل من سعفة القدم يُشتبه؟"},"options":[{"letter":"A","en":"Ulcerative type with possible bacterial superinfection","ar":"النوع التقرحي مع احتمال عدوى بكتيرية ثانوية"},{"letter":"B","en":"Simple moccasin type only","ar":"النوع البسيط بشكل الحذاء فقط"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"White superficial onychomycosis","ar":"فطار الأظافر الأبيض السطحي"}],"correct":"A","explanation":{"en":"Ulcerative tinea pedis is severe and is associated with erosions, ulcers, pain, odor, and secondary bacterial infection, especially in diabetes or immunosuppression.","ar":"النوع التقرحي شديد ويرتبط بالتآكلات والقرح والألم والرائحة والعدوى البكتيرية الثانوية، خاصة مع السكري أو ضعف المناعة."},"reasoning":{"en":"The red flags and high-risk host make this more than uncomplicated superficial scaling.","ar":"علامات الشدة ووجود مريض عالي الخطورة تجعل الحالة أكثر من مجرد قشور سطحية بسيطة."},"image":null},{"id":"Q022","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Case","difficulty":"Medium","source":"PDF p. 51","question":{"en":"A patient with untreated tinea pedis develops unilateral leg erythema, warmth, and fever. What complication is most concerning?","ar":"مريض لديه سعفة قدم غير معالجة ثم ظهر احمرار وسخونة بالساق مع حمى. ما المضاعفة الأكثر إثارة للقلق؟"},"options":[{"letter":"A","en":"Secondary bacterial cellulitis","ar":"التهاب نسيج خلوي بكتيري ثانوي"},{"letter":"B","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"},{"letter":"C","en":"Tinea incognito","ar":"السعفة المتخفية"},{"letter":"D","en":"Tinea nigra","ar":"السعفة السوداء"}],"correct":"A","explanation":{"en":"Fissures from tinea pedis can act as portals of entry for bacteria and lead to cellulitis, erysipelas, or lymphangitis.","ar":"يمكن أن تعمل تشققات سعفة القدم كبوابة دخول للبكتيريا وتؤدي إلى التهاب النسيج الخلوي أو الحمرة أو التهاب الأوعية اللمفاوية."},"reasoning":{"en":"Systemic fever and spreading leg inflammation indicate a bacterial complication rather than worsening superficial fungus alone.","ar":"الحمى والالتهاب المنتشر بالساق يشيران إلى مضاعفة بكتيرية لا إلى زيادة الفطر السطحي وحده."},"image":null},{"id":"Q023","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Treatment","difficulty":"Medium","source":"PDF p. 51","question":{"en":"What is an appropriate first-line treatment for uncomplicated interdigital tinea pedis?","ar":"ما العلاج الأولي المناسب لسعفة القدم غير المعقدة بين الأصابع؟"},"options":[{"letter":"A","en":"Topical terbinafine with moisture control","ar":"تيربينافين موضعي مع التحكم في الرطوبة"},{"letter":"B","en":"Oral ketoconazole","ar":"كيتوكونازول فموي"},{"letter":"C","en":"Topical nystatin alone","ar":"نيستاتين موضعي وحده"},{"letter":"D","en":"IV vancomycin","ar":"فانكومايسين وريدي"}],"correct":"A","explanation":{"en":"A topical allylamine is effective for localized tinea pedis, and drying the toe webs helps eradicate the moist environment that supports recurrence.","ar":"يعد الأليلامين الموضعي فعالًا في سعفة القدم الموضعية، كما يساعد تجفيف الفراغات بين الأصابع في إزالة البيئة الرطبة التي تدعم التكرار."},"reasoning":{"en":"Treat both the organism and the local predisposing environment.","ar":"يجب علاج الكائن المسبب والبيئة الموضعية المهيئة معًا."},"image":null},{"id":"Q024","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Treatment","difficulty":"Medium","source":"PDF p. 51","question":{"en":"A chronic extensive tinea pedis infection has failed correctly applied topical therapy. Which oral regimen from the chapter is appropriate?","ar":"عدوى سعفة قدم مزمنة واسعة لم تستجب لعلاج موضعي استُخدم بطريقة صحيحة. أي نظام فموي مذكور في الفصل مناسب؟"},"options":[{"letter":"A","en":"Terbinafine 250 mg daily for 2 weeks","ar":"تيربينافين 250 مجم يوميًا لمدة أسبوعين"},{"letter":"B","en":"Nystatin 500,000 units once","ar":"نيستاتين 500000 وحدة مرة واحدة"},{"letter":"C","en":"Fluconazole 150 mg once only","ar":"فلوكونازول 150 مجم مرة واحدة فقط"},{"letter":"D","en":"Griseofulvin for one day","ar":"جريزوفولفين ليوم واحد"}],"correct":"A","explanation":{"en":"Oral terbinafine is a listed option for refractory, extensive, or chronic tinea pedis.","ar":"التيربينافين الفموي خيار مذكور للحالات المقاومة أو الواسعة أو المزمنة من سعفة القدم."},"reasoning":{"en":"Failure of adequate topical treatment plus extensive disease meets the threshold for systemic therapy.","ar":"فشل العلاج الموضعي الصحيح مع انتشار المرض يبرر الانتقال إلى علاج جهازي."},"image":null},{"id":"Q025","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Treatment","difficulty":"Medium","source":"PDF p. 51","question":{"en":"Which adjunct is most appropriate for markedly macerated interdigital tinea pedis?","ar":"ما العلاج المساعد الأنسب لسعفة قدم بين الأصابع مع تميع شديد؟"},"options":[{"letter":"A","en":"Burow solution soaks and toe-web drying","ar":"كمادات محلول بورو وتجفيف الفراغات بين الأصابع"},{"letter":"B","en":"Occlusive petroleum dressings continuously","ar":"ضمادات بترولية مغلقة باستمرار"},{"letter":"C","en":"High-potency steroid monotherapy","ar":"كورتيزون قوي موضعي وحده"},{"letter":"D","en":"Warm tight footwear","ar":"أحذية دافئة ضيقة"}],"correct":"A","explanation":{"en":"Aluminum acetate preparations can help dry macerated skin; gauze or cotton between toes can maintain separation and dryness.","ar":"يمكن لمستحضرات أسيتات الألومنيوم المساعدة في تجفيف الجلد المتميع، كما يفيد وضع شاش أو قطن بين الأصابع للحفاظ على الفصل والجفاف."},"reasoning":{"en":"Reducing moisture reverses the main local condition that sustains interdigital infection.","ar":"تقليل الرطوبة يعالج العامل الموضعي الأساسي الذي يحافظ على العدوى بين الأصابع."},"image":null},{"id":"Q026","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Treatment","difficulty":"Hard","source":"PDF p. 52","question":{"en":"A patient improves after one week of topical antifungal treatment and asks to stop immediately. What is the best advice?","ar":"تحسن المريض بعد أسبوع من العلاج الموضعي وسأل عن التوقف فورًا. ما النصيحة الأفضل؟"},"options":[{"letter":"A","en":"Complete the recommended course and continue preventive foot care","ar":"إكمال المدة الموصى بها والاستمرار على العناية الوقائية بالقدم"},{"letter":"B","en":"Stop now because symptoms equal cure","ar":"التوقف لأن اختفاء الأعراض يعني الشفاء"},{"letter":"C","en":"Replace the antifungal with steroid alone","ar":"استبدال المضاد الفطري بكورتيزون وحده"},{"letter":"D","en":"Begin prophylactic antibiotics","ar":"بدء مضاد حيوي وقائي"}],"correct":"A","explanation":{"en":"Clinical improvement can precede complete fungal eradication. Completing therapy and controlling moisture reduces relapse.","ar":"قد يسبق التحسن السريري القضاء الكامل على الفطر، لذا فإن إكمال العلاج والتحكم في الرطوبة يقللان الانتكاس."},"reasoning":{"en":"Stopping at symptom relief leaves residual infection and the same environmental risk factors in place.","ar":"الإيقاف عند تحسن الأعراض قد يترك عدوى متبقية وعوامل خطورة بيئية مستمرة."},"image":null},{"id":"Q027","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Image","difficulty":"Medium","source":"PDF p. 52","question":{"en":"The image shows maceration and scaling concentrated in a toe web. Which subtype is most likely?","ar":"توضح الصورة تميعًا وقشورًا تتركز في الفراغ بين أصابع القدم. ما النوع الأرجح؟"},"options":[{"letter":"A","en":"Interdigital tinea pedis","ar":"سعفة القدم بين الأصابع"},{"letter":"B","en":"Moccasin-type tinea pedis","ar":"سعفة القدم بشكل الحذاء"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Kerion","ar":"الكيريون"}],"correct":"A","explanation":{"en":"Toe-web maceration, scaling, and fissuring are characteristic of the interdigital form.","ar":"التميع والقشور والتشققات بين الأصابع تميز الشكل بين الأصابع."},"reasoning":{"en":"The image localizes disease to a moist web space rather than the entire sole.","ar":"تحدد الصورة المرض في فراغ رطب بين الأصابع وليس في باطن القدم كله."},"image":"assets/images/chapters/fungal/fungal-q027.webp"},{"id":"Q028","topic":"tinea-pedis","topicEn":"Tinea Pedis","topicAr":"سعفة القدم","type":"Image","difficulty":"Medium","source":"PDF p. 52","question":{"en":"The image shows diffuse dry scaling involving the plantar and lateral surfaces of the foot. What is the pattern?","ar":"توضح الصورة قشورًا جافة منتشرة على السطح الأخمصي والجوانب. ما النمط؟"},"options":[{"letter":"A","en":"Hyperkeratotic moccasin-type tinea pedis","ar":"سعفة القدم مفرطة التقرن بشكل الحذاء"},{"letter":"B","en":"Interdigital tinea pedis","ar":"سعفة القدم بين الأصابع"},{"letter":"C","en":"Ulcerative tinea pedis","ar":"سعفة القدم التقرحية"},{"letter":"D","en":"Cutaneous candidiasis","ar":"داء المبيضات الجلدي"}],"correct":"A","explanation":{"en":"The broad dry hyperkeratotic distribution over the sole and sides resembles a moccasin.","ar":"التوزيع الواسع الجاف مفرط التقرن على الباطن والجوانب يشبه الحذاء المغلق."},"reasoning":{"en":"Distribution is the key image clue, distinguishing this from focal toe-web disease.","ar":"التوزيع هو المفتاح في الصورة ويميزه عن المرض الموضعي بين الأصابع."},"image":"assets/images/chapters/fungal/fungal-q028.webp"},{"id":"Q029","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"MCQ","difficulty":"Medium","source":"PDF p. 53","question":{"en":"Which clinical feature helps distinguish tinea cruris from candidal intertrigo in a male patient?","ar":"أي علامة سريرية تساعد على تمييز سعفة الأرفاغ من التهاب الثنيات بالمبيضات لدى الرجل؟"},"options":[{"letter":"A","en":"Relative sparing of the scrotum","ar":"سلامة كيس الصفن نسبيًا"},{"letter":"B","en":"Satellite pustules on the scrotum","ar":"بثور تابعة على كيس الصفن"},{"letter":"C","en":"Moist glazed erythema","ar":"حمامى رطبة لامعة"},{"letter":"D","en":"Oral white plaques","ar":"لويحات بيضاء بالفم"}],"correct":"A","explanation":{"en":"Tinea cruris typically affects the groin and proximal thighs while usually sparing the scrotum; candidiasis commonly involves it.","ar":"تصيب سعفة الأرفاغ عادةً الأربية وأعلى الفخذين مع سلامة كيس الصفن غالبًا، بينما قد تصيبه المبيضات."},"reasoning":{"en":"Anatomic distribution is a high-yield differentiator when morphology overlaps.","ar":"التوزيع التشريحي عامل تمييز مهم عندما تتشابه أشكال الآفات."},"image":null},{"id":"Q030","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"MCQ","difficulty":"Easy","source":"PDF p. 53","question":{"en":"What is the most common causative dermatophyte of tinea cruris?","ar":"ما الفطر الجلدي الأكثر شيوعًا في سعفة الأرفاغ؟"},"options":[{"letter":"A","en":"Trichophyton rubrum","ar":"Trichophyton rubrum"},{"letter":"B","en":"Malassezia furfur","ar":"Malassezia furfur"},{"letter":"C","en":"Candida glabrata","ar":"Candida glabrata"},{"letter":"D","en":"Hortaea werneckii","ar":"Hortaea werneckii"}],"correct":"A","explanation":{"en":"T. rubrum is the most common organism in tinea cruris.","ar":"يعد T. rubrum أكثر الكائنات شيوعًا في سعفة الأرفاغ."},"reasoning":{"en":"The same chronic dermatophyte frequently affects feet and spreads to the groin.","ar":"الفطر الجلدي المزمن نفسه يصيب القدمين كثيرًا وقد ينتقل إلى الأربية."},"image":null},{"id":"Q031","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"MCQ","difficulty":"Medium","source":"PDF p. 54","question":{"en":"Which lesion morphology is most typical of tinea cruris?","ar":"أي شكل للآفة هو الأكثر شيوعًا في سعفة الأرفاغ؟"},"options":[{"letter":"A","en":"Pruritic annular plaque with an active scaly border and central clearing","ar":"لويحة حلقية حاكة بحافة نشطة متقشرة وتفريغ مركزي"},{"letter":"B","en":"Deep ulcer with black eschar","ar":"قرحة عميقة بقشرة سوداء"},{"letter":"C","en":"Flaccid bullae with honey crust","ar":"فقاعات رخوة بقشور عسلية"},{"letter":"D","en":"Non-scaly fixed purpura","ar":"فرفرية ثابتة بلا قشور"}],"correct":"A","explanation":{"en":"Dermatophyte growth is most active at the advancing edge, producing a raised scaly border with partial central clearing.","ar":"يكون نمو الفطر الجلدي أنشط عند الحافة المتقدمة، فينتج حد مرتفع متقشر مع تفريغ مركزي جزئي."},"reasoning":{"en":"The active border and centrifugal spread indicate ringworm rather than bacterial or vascular disease.","ar":"الحافة النشطة والانتشار للخارج يدلان على السعفة لا على مرض بكتيري أو وعائي."},"image":null},{"id":"Q032","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"MCQ","difficulty":"Easy","source":"PDF p. 54","question":{"en":"Which coexisting condition is a common reservoir for recurrent tinea cruris?","ar":"أي حالة مصاحبة تعد مستودعًا شائعًا لتكرار سعفة الأرفاغ؟"},"options":[{"letter":"A","en":"Tinea pedis","ar":"سعفة القدم"},{"letter":"B","en":"Aphthous ulcer","ar":"قرحة فموية قلاعية"},{"letter":"C","en":"Acne vulgaris","ar":"حب الشباب"},{"letter":"D","en":"Herpes labialis","ar":"هربس الشفاه"}],"correct":"A","explanation":{"en":"Infected feet and toenails can reseed the groin through hands, clothing, or towels.","ar":"يمكن للقدمين والأظافر المصابة إعادة عدوى الأربية عن طريق اليدين أو الملابس أو المناشف."},"reasoning":{"en":"Treating only the groin leaves the fungal reservoir intact.","ar":"علاج الأربية وحدها يترك مستودع الفطر دون علاج."},"image":null},{"id":"Q033","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"MCQ","difficulty":"Medium","source":"PDF p. 54","question":{"en":"Why should topical corticosteroid-antifungal combination creams generally be avoided in uncomplicated tinea cruris?","ar":"لماذا يجب تجنب كريمات الكورتيزون المركبة مع مضاد فطري عادةً في سعفة الأرفاغ غير المعقدة؟"},"options":[{"letter":"A","en":"They can mask and worsen the infection, causing tinea incognito","ar":"قد تخفي العدوى وتزيدها وتسبب السعفة المتخفية"},{"letter":"B","en":"They permanently stain the skin green","ar":"تصبغ الجلد باللون الأخضر دائمًا"},{"letter":"C","en":"They eliminate all fungal cultures","ar":"تقضي على كل المزارع الفطرية"},{"letter":"D","en":"They always cause renal failure","ar":"تسبب فشلًا كلويًا دائمًا"}],"correct":"A","explanation":{"en":"Steroids suppress local inflammation and immunity, altering the appearance while allowing fungal proliferation.","ar":"يثبط الكورتيزون الالتهاب والمناعة الموضعية فيغير شكل الآفة ويسمح بتكاثر الفطر."},"reasoning":{"en":"Temporary symptom relief can be misleading while the organism spreads.","ar":"قد يكون التحسن المؤقت للأعراض مضللًا بينما يستمر انتشار الفطر."},"image":null},{"id":"Q034","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"MCQ","difficulty":"Medium","source":"PDF p. 54","question":{"en":"Which emerging organism is associated with difficult-to-treat and sometimes terbinafine-resistant tinea cruris?","ar":"أي كائن ناشئ يرتبط بسعفة أرفاغ صعبة العلاج وقد تكون مقاومة للتيربينافين؟"},"options":[{"letter":"A","en":"Trichophyton indotineae","ar":"Trichophyton indotineae"},{"letter":"B","en":"Microsporum audouinii","ar":"Microsporum audouinii"},{"letter":"C","en":"Candida parapsilosis","ar":"Candida parapsilosis"},{"letter":"D","en":"Malassezia globosa","ar":"Malassezia globosa"}],"correct":"A","explanation":{"en":"T. indotineae is an emerging dermatophyte linked to extensive disease and terbinafine resistance in some regions.","ar":"يعد T. indotineae فطرًا جلديًا ناشئًا يرتبط بمرض واسع ومقاومة للتيربينافين في بعض المناطق."},"reasoning":{"en":"Persistent disease despite adherence should prompt reassessment of diagnosis, reservoirs, and resistance.","ar":"استمرار المرض رغم الالتزام يستدعي إعادة تقييم التشخيص والمستودعات والمقاومة."},"image":null},{"id":"Q035","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Case","difficulty":"Medium","source":"PDF p. 53","question":{"en":"An obese man in a hot climate has an intensely itchy, sharply demarcated scaly plaque on the inner thighs with central clearing; the scrotum is spared. What is the most likely diagnosis?","ar":"رجل بدين في مناخ حار لديه لويحة شديدة الحكة محددة الحواف ومتقشرة بأعلى الفخذين مع تفريغ مركزي وكيس الصفن سليم. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Tinea cruris","ar":"سعفة الأرفاغ"},{"letter":"B","en":"Candidal intertrigo","ar":"التهاب الثنيات بالمبيضات"},{"letter":"C","en":"Erythrasma","ar":"الإريثراسما"},{"letter":"D","en":"Inverse psoriasis","ar":"الصدفية العكسية"}],"correct":"A","explanation":{"en":"The active scaly border, central clearing, thigh distribution, and scrotal sparing are classic for tinea cruris.","ar":"الحافة النشطة المتقشرة والتفريغ المركزي وتوزيع أعلى الفخذ وسلامة كيس الصفن علامات كلاسيكية لسعفة الأرفاغ."},"reasoning":{"en":"Multiple concordant features are more specific than itching alone.","ar":"اجتماع عدة علامات متوافقة أكثر نوعية من الحكة وحدها."},"image":null},{"id":"Q036","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Case","difficulty":"Medium","source":"PDF p. 54","question":{"en":"A woman has moist beefy-red groin erythema involving the vulvar folds with satellite pustules. Which diagnosis is more likely than tinea cruris?","ar":"امرأة لديها حمامى رطبة حمراء زاهية بالأربية تشمل ثنيات الفرج مع بثور تابعة. أي تشخيص أرجح من سعفة الأرفاغ؟"},"options":[{"letter":"A","en":"Candidal intertrigo","ar":"التهاب الثنيات بالمبيضات"},{"letter":"B","en":"Tinea pedis","ar":"سعفة القدم"},{"letter":"C","en":"Pityriasis versicolor","ar":"النخالية المبرقشة"},{"letter":"D","en":"Tinea nigra","ar":"السعفة السوداء"}],"correct":"A","explanation":{"en":"Moist glazed erythema involving genital folds with satellite papules or pustules favors Candida.","ar":"الحمامى الرطبة اللامعة التي تشمل الثنيات التناسلية مع حطاطات أو بثور تابعة ترجح المبيضات."},"reasoning":{"en":"Satellite lesions and involvement of normally spared genital skin shift the diagnosis away from dermatophyte tinea.","ar":"الآفات التابعة وإصابة الجلد التناسلي الذي يُحفظ عادةً في السعفة يرجحان المبيضات."},"image":null},{"id":"Q037","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Case","difficulty":"Easy","source":"PDF p. 55","question":{"en":"A patient completes an appropriate topical course for tinea cruris, improves, then relapses every month. He also has untreated scaling between the toes. What is the most likely reason?","ar":"أكمل مريض علاجًا موضعيًا مناسبًا لسعفة الأرفاغ وتحسن ثم انتكس شهريًا، ولديه قشور غير معالجة بين أصابع القدم. ما السبب الأرجح؟"},"options":[{"letter":"A","en":"Reinfection from untreated tinea pedis","ar":"إعادة العدوى من سعفة قدم غير معالجة"},{"letter":"B","en":"Drug-induced lupus","ar":"ذئبة دوائية"},{"letter":"C","en":"Immediate antifungal tolerance","ar":"تحمل فوري للمضاد الفطري"},{"letter":"D","en":"Viral superinfection","ar":"عدوى فيروسية ثانوية"}],"correct":"A","explanation":{"en":"The feet can serve as a persistent reservoir that repeatedly inoculates the groin.","ar":"قد تعمل القدم كمستودع دائم يعيد تلقيح منطقة الأربية مرارًا."},"reasoning":{"en":"Recurrence despite a successful local course requires searching for reservoirs and behavioral factors.","ar":"التكرار رغم نجاح العلاج الموضعي يستلزم البحث عن مستودعات العدوى والعوامل السلوكية."},"image":null},{"id":"Q038","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Case","difficulty":"Medium","source":"PDF p. 54","question":{"en":"A groin rash became less scaly after a potent steroid but expanded with irregular borders and pustules. What is the most likely transformation?","ar":"أصبح طفح الأربية أقل تقشرًا بعد كورتيزون قوي لكنه اتسع بحواف غير منتظمة وبثور. ما التحول الأرجح؟"},"options":[{"letter":"A","en":"Tinea incognito","ar":"السعفة المتخفية"},{"letter":"B","en":"Spontaneous cure","ar":"شفاء تلقائي"},{"letter":"C","en":"Bacterial erysipelas","ar":"الحمرة البكتيرية"},{"letter":"D","en":"Vitiligo","ar":"البهاق"}],"correct":"A","explanation":{"en":"Steroid exposure can suppress typical inflammation while permitting dermatophyte spread and an atypical pustular appearance.","ar":"قد يثبط الكورتيزون الالتهاب المعتاد بينما يسمح بانتشار الفطر وظهور شكل غير نمطي مع بثور."},"reasoning":{"en":"The paradox of temporary cosmetic improvement with progressive spread is characteristic of steroid-modified tinea.","ar":"مفارقة التحسن الشكلي المؤقت مع استمرار الانتشار تميز السعفة المعدلة بالكورتيزون."},"image":null},{"id":"Q039","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Case","difficulty":"Easy","source":"PDF p. 55","question":{"en":"A patient has persistent tinea cruris despite correct treatment. KOH remains positive. He uses tight synthetic clothing and does not change after exercise. What factor should be corrected first?","ar":"مريض لديه سعفة أرفاغ مستمرة رغم العلاج الصحيح وما زال KOH إيجابيًا. يرتدي ملابس صناعية ضيقة ولا يغيرها بعد الرياضة. ما العامل الذي يجب تصحيحه؟"},"options":[{"letter":"A","en":"Moisture and occlusion","ar":"الرطوبة والانغلاق"},{"letter":"B","en":"Low dietary calcium","ar":"انخفاض الكالسيوم الغذائي"},{"letter":"C","en":"Sunlight exposure","ar":"التعرض للشمس"},{"letter":"D","en":"Excess water intake","ar":"زيادة شرب الماء"}],"correct":"A","explanation":{"en":"Tight synthetic garments and retained sweat create a warm, moist environment that promotes persistence and recurrence.","ar":"تخلق الملابس الصناعية الضيقة والعرق المحتبس بيئة دافئة رطبة تدعم استمرار العدوى وتكرارها."},"reasoning":{"en":"Correct therapy may fail operationally if the local ecological driver is unchanged.","ar":"قد يفشل العلاج الصحيح عمليًا إذا لم يتغير العامل البيئي الموضعي المحفز."},"image":null},{"id":"Q040","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Treatment","difficulty":"Medium","source":"PDF p. 54","question":{"en":"What is an appropriate initial treatment for mild localized tinea cruris?","ar":"ما العلاج الأولي المناسب لسعفة الأرفاغ الموضعية البسيطة؟"},"options":[{"letter":"A","en":"Topical terbinafine or an azole for 2–4 weeks","ar":"تيربينافين موضعي أو أزول لمدة 2–4 أسابيع"},{"letter":"B","en":"Oral amphotericin B","ar":"أمفوتيريسين ب فموي"},{"letter":"C","en":"High-potency steroid alone","ar":"كورتيزون موضعي قوي وحده"},{"letter":"D","en":"Nystatin as the preferred dermatophyte drug","ar":"نيستاتين كدواء مفضل للفطريات الجلدية"}],"correct":"A","explanation":{"en":"Localized disease is usually treated with a topical allylamine or azole applied once or twice daily.","ar":"يعالج المرض الموضعي عادةً بأليلامين أو أزول موضعي مرة أو مرتين يوميًا."},"reasoning":{"en":"The infection is accessible in superficial keratin and does not initially require systemic therapy.","ar":"العدوى موجودة في كيراتين سطحي يسهل الوصول إليه ولا تحتاج مبدئيًا إلى علاج جهازي."},"image":null},{"id":"Q041","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Treatment","difficulty":"Hard","source":"PDF p. 55","question":{"en":"Which management plan best addresses recurrent tinea cruris?","ar":"أي خطة علاجية تعالج تكرار سعفة الأرفاغ بصورة أفضل؟"},"options":[{"letter":"A","en":"Treat the groin and coexisting tinea pedis, keep folds dry, and decontaminate clothing","ar":"علاج الأربية وسعفة القدم المصاحبة وتجفيف الثنيات وتنظيف الملابس"},{"letter":"B","en":"Treat the groin only and ignore the feet","ar":"علاج الأربية فقط وتجاهل القدمين"},{"letter":"C","en":"Use steroid monotherapy whenever itching recurs","ar":"استخدام كورتيزون وحده عند عودة الحكة"},{"letter":"D","en":"Share towels to build immunity","ar":"مشاركة المناشف لبناء المناعة"}],"correct":"A","explanation":{"en":"Successful recurrence prevention requires eradication of reservoirs and correction of heat, moisture, and fomite exposure.","ar":"تتطلب الوقاية من التكرار القضاء على المستودعات وتصحيح الحرارة والرطوبة والتعرض للأدوات الملوثة."},"reasoning":{"en":"A multi-site reinfection cycle cannot be broken by treating one visible site alone.","ar":"لا يمكن كسر دورة إعادة العدوى متعددة المواقع بعلاج الموقع الظاهر وحده."},"image":null},{"id":"Q042","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Treatment","difficulty":"Medium","source":"PDF p. 55","question":{"en":"A widespread recurrent case has failed topical treatment. Which oral option is listed in the chapter?","ar":"حالة واسعة ومتكررة لم تستجب للعلاج الموضعي. أي خيار فموي مذكور في الفصل؟"},"options":[{"letter":"A","en":"Terbinafine 250 mg once daily for 2–4 weeks","ar":"تيربينافين 250 مجم مرة يوميًا لمدة 2–4 أسابيع"},{"letter":"B","en":"Nystatin 100,000 units once","ar":"نيستاتين 100000 وحدة مرة واحدة"},{"letter":"C","en":"Oral ketoconazole indefinitely","ar":"كيتوكونازول فموي دون مدة محددة"},{"letter":"D","en":"Azithromycin for 3 days","ar":"أزيثرومايسين 3 أيام"}],"correct":"A","explanation":{"en":"Systemic terbinafine is an option for extensive, refractory, or recurrent tinea cruris.","ar":"يعد التيربينافين الجهازي خيارًا لسعفة الأرفاغ الواسعة أو المقاومة أو المتكررة."},"reasoning":{"en":"Extent and failure of adequate topical therapy justify escalation while resistance and diagnosis are reassessed.","ar":"الانتشار وفشل العلاج الموضعي المناسب يبرران التصعيد مع إعادة تقييم المقاومة والتشخيص."},"image":null},{"id":"Q043","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Treatment","difficulty":"Hard","source":"PDF p. 55","question":{"en":"A patient with suspected terbinafine-resistant tinea cruris has persistent positive microscopy despite adherence. What is the best next principle?","ar":"مريض مشتبه في سعفة أرفاغ مقاومة للتيربينافين مع فحص مجهري إيجابي مستمر رغم الالتزام. ما المبدأ التالي الأفضل؟"},"options":[{"letter":"A","en":"Obtain species identification/susceptibility where available and choose an alternative systemic agent","ar":"تحديد النوع والحساسية إن أمكن واختيار دواء جهازي بديل"},{"letter":"B","en":"Increase topical steroid potency","ar":"زيادة قوة الكورتيزون الموضعي"},{"letter":"C","en":"Stop all antifungal therapy permanently","ar":"إيقاف كل العلاج الفطري نهائيًا"},{"letter":"D","en":"Assume the KOH is irrelevant","ar":"اعتبار KOH غير مهم"}],"correct":"A","explanation":{"en":"Persistent confirmed infection may reflect resistant T. indotineae or another diagnosis; targeted reassessment is safer than blind steroid escalation.","ar":"قد تعكس العدوى المؤكدة المستمرة T. indotineae مقاومًا أو تشخيصًا آخر، وإعادة التقييم الموجهة أكثر أمانًا من زيادة الكورتيزون عشوائيًا."},"reasoning":{"en":"Objective persistence plus adherence changes the problem from compliance to organism or diagnosis.","ar":"استمرار العدوى موضوعيًا مع الالتزام ينقل المشكلة من الالتزام إلى الكائن أو التشخيص."},"image":null},{"id":"Q044","topic":"tinea-cruris","topicEn":"Tinea Cruris","topicAr":"سعفة الأرفاغ","type":"Image","difficulty":"Hard","source":"PDF p. 53","question":{"en":"The image shows an erythematous plaque in the groin with an active peripheral border. Which diagnosis is most likely?","ar":"توضح الصورة لويحة حمامية بالأربية ذات حافة محيطية نشطة. ما التشخيص الأرجح؟"},"options":[{"letter":"A","en":"Tinea cruris","ar":"سعفة الأرفاغ"},{"letter":"B","en":"Tinea capitis","ar":"سعفة الرأس"},{"letter":"C","en":"Tinea nigra","ar":"السعفة السوداء"},{"letter":"D","en":"Oral candidiasis","ar":"داء المبيضات الفموي"}],"correct":"A","explanation":{"en":"The location and active scaly edge are typical of dermatophyte infection of the groin.","ar":"الموقع والحافة النشطة المتقشرة نموذجيان لعدوى فطرية جلدية بالأربية."},"reasoning":{"en":"Image interpretation should combine site with border morphology.","ar":"يجب الجمع بين موقع الآفة وشكل الحافة عند تفسير الصورة."},"image":"assets/images/chapters/fungal/fungal-q044.webp"},{"id":"Q045","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"MCQ","difficulty":"Medium","source":"PDF p. 57","question":{"en":"Which is the most common clinical subtype of onychomycosis?","ar":"ما النوع السريري الأكثر شيوعًا من فطار الأظافر؟"},"options":[{"letter":"A","en":"Distal lateral subungual onychomycosis","ar":"فطار الأظافر تحت الظفر البعيد الجانبي"},{"letter":"B","en":"Proximal subungual onychomycosis","ar":"فطار الأظافر تحت الظفر القريب"},{"letter":"C","en":"Endonyx onychomycosis","ar":"فطار الأظافر داخل الصفيحة"},{"letter":"D","en":"Total dystrophic onychomycosis","ar":"فطار الأظافر الضموري الكلي"}],"correct":"A","explanation":{"en":"DLSO is the most common subtype and usually begins at the distal or lateral nail edge.","ar":"DLSO هو النوع الأكثر شيوعًا ويبدأ عادةً عند الحافة البعيدة أو الجانبية للظفر."},"reasoning":{"en":"The direction of invasion from the distal-lateral edge toward the matrix defines the common pattern.","ar":"اتجاه الغزو من الحافة البعيدة الجانبية نحو المصفوفة يحدد النمط الشائع."},"image":null},{"id":"Q046","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"MCQ","difficulty":"Easy","source":"PDF p. 57","question":{"en":"Which organism most commonly causes distal lateral subungual onychomycosis?","ar":"أي كائن يسبب غالبًا فطار الأظافر تحت الظفر البعيد الجانبي؟"},"options":[{"letter":"A","en":"Trichophyton rubrum","ar":"Trichophyton rubrum"},{"letter":"B","en":"Malassezia furfur","ar":"Malassezia furfur"},{"letter":"C","en":"Hortaea werneckii","ar":"Hortaea werneckii"},{"letter":"D","en":"Bartonella henselae","ar":"Bartonella henselae"}],"correct":"A","explanation":{"en":"DLSO is caused predominantly by T. rubrum.","ar":"ينتج DLSO في الغالب عن T. rubrum."},"reasoning":{"en":"The chronic dermatophyte commonly responsible for feet also invades the nail from the distal edge.","ar":"الفطر الجلدي المزمن الشائع في القدم يغزو الظفر أيضًا من الحافة البعيدة."},"image":null},{"id":"Q047","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"MCQ","difficulty":"Medium","source":"PDF p. 57","question":{"en":"Which finding is characteristic of white superficial onychomycosis?","ar":"أي علامة تميز فطار الأظافر الأبيض السطحي؟"},"options":[{"letter":"A","en":"Chalky white superficial patches that can be scraped off","ar":"بقع بيضاء طباشيرية سطحية يمكن كشطها"},{"letter":"B","en":"Pigment beginning only at the proximal fold","ar":"صبغة تبدأ فقط عند الثنية القريبة"},{"letter":"C","en":"No surface abnormality","ar":"عدم وجود تغير سطحي"},{"letter":"D","en":"Painful purulent nail-fold abscess","ar":"خراج صديدي مؤلم بثنية الظفر"}],"correct":"A","explanation":{"en":"WSO affects the superficial nail plate and produces soft white patches that are often easily scraped.","ar":"يصيب WSO سطح صفيحة الظفر ويسبب بقعًا بيضاء رخوة يمكن كشطها بسهولة غالبًا."},"reasoning":{"en":"A removable superficial lesion points to surface invasion rather than subungual disease.","ar":"الآفة السطحية القابلة للكشط تشير إلى غزو السطح بدل المرض تحت الظفر."},"image":null},{"id":"Q048","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"MCQ","difficulty":"Easy","source":"PDF p. 57","question":{"en":"Proximal subungual onychomycosis should prompt evaluation for which condition?","ar":"فطار الأظافر تحت الظفر القريب يستدعي تقييم أي حالة؟"},"options":[{"letter":"A","en":"Immunosuppression, including HIV","ar":"ضعف المناعة بما فيه HIV"},{"letter":"B","en":"Isolated iron deficiency only","ar":"نقص الحديد المعزول فقط"},{"letter":"C","en":"Seasonal allergic rhinitis","ar":"حساسية الأنف الموسمية"},{"letter":"D","en":"Migraine","ar":"الصداع النصفي"}],"correct":"A","explanation":{"en":"PSO is uncommon and may be a marker of significant immunosuppression.","ar":"PSO غير شائع وقد يكون علامة على ضعف مناعي مهم."},"reasoning":{"en":"An unusual proximal route of invasion is a clinical clue to impaired host defense.","ar":"بداية الغزو من الناحية القريبة غير المعتادة تعد دليلًا على ضعف دفاعات العائل."},"image":null},{"id":"Q049","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"MCQ","difficulty":"Medium","source":"PDF p. 57","question":{"en":"Which feature differentiates endonyx onychomycosis from typical subungual disease?","ar":"أي علامة تميز فطار الأظافر داخل الصفيحة عن المرض المعتاد تحت الظفر؟"},"options":[{"letter":"A","en":"No subungual hyperkeratosis","ar":"عدم وجود فرط تقرن تحت الظفر"},{"letter":"B","en":"Always involves the proximal fold","ar":"يصيب الثنية القريبة دائمًا"},{"letter":"C","en":"Always causes satellite pustules","ar":"يسبب بثورًا تابعة دائمًا"},{"letter":"D","en":"Only affects the skin","ar":"يصيب الجلد فقط"}],"correct":"A","explanation":{"en":"Endonyx infection is confined to the interior of the nail plate without nail-bed involvement or subungual hyperkeratosis.","ar":"تقتصر عدوى Endonyx على داخل صفيحة الظفر دون إصابة سرير الظفر أو فرط تقرن تحته."},"reasoning":{"en":"Absence of nail-bed debris indicates intraplate rather than subungual infection.","ar":"غياب الحطام تحت الظفر يشير إلى عدوى داخل الصفيحة لا تحتها."},"image":null},{"id":"Q050","topic":"onychomycosis","topicEn":"Onychomycosis","topicAr":"فطار الأظافر","type":"MCQ","difficulty":"Medium","source":"PDF p. 58","question":{"en":"What is a dermatophytoma?","ar":"ما هو الـ dermatophytoma؟"},"options":[{"letter":"A","en":"A dense compact fungal mass within the nail plate","ar":"كتلة فطرية كثيفة مدمجة داخل صفيحة الظفر"},{"letter":"B","en":"A bacterial abscess around the nail","ar":"خراج بكتيري حول الظفر"},{"letter":"C","en":"A benign bone tumor","ar":"ورم عظمي حميد"},{"letter":"D","en":"A pigment-free nail streak","ar":"خط عديم الصبغة بالظفر"}],"correct":"A","explanation":{"en":"A dermatophytoma appears as a linear or oval white, yellow, or orange band and may be resistant to oral therapy.","ar":"يظهر dermatophytoma كشريط خطي أو بيضاوي أبيض أو أصفر أو برتقالي وقد يقاوم العلاج الفموي."},"reasoning":{"en":"A compact fungal bio-burden limits drug penetration and predicts treatment difficulty.","ar":"الكتلة الفطرية المدمجة تقلل اختراق الدواء وتتنبأ بصعوبة العلاج."},"image":null}];
